import{_ as p,c as e,o as r,ae as t}from"./chunks/framework.BvcDoAct.js";const h=JSON.parse('{"title":"TAIKI (BMSG TRAINEE)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/21_TAIKI.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/21_TAIKI.md"}'),i={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/21_TAIKI.md"};function n(o,a,I,T,S,A){return r(),e("div",null,[...a[0]||(a[0]=[t('<p>Talk about BMSG - 21</p><h1 id="taiki-bmsg-trainee" tabindex="-1">TAIKI (BMSG TRAINEE) <a class="header-anchor" href="#taiki-bmsg-trainee" aria-label="Permalink to &quot;TAIKI (BMSG TRAINEE)&quot;">​</a></h1><h3 id="「taiki一路累积至今的东西绝对没有错」——社长的这句话-成了我真正的底气" tabindex="-1">「TAIKI一路累积至今的东西绝对没有错」——社长的这句话，成了我真正的底气 <a class="header-anchor" href="#「taiki一路累积至今的东西绝对没有错」——社长的这句话-成了我真正的底气" aria-label="Permalink to &quot;「TAIKI一路累积至今的东西绝对没有错」——社长的这句话，成了我真正的底气&quot;">​</a></h3><p><em>TAIKI：2007年7月28日出生，东京都出身</em></p><p>————从认识到现在将近4年，一直看着SKY-HI先生，有感觉到什么变化吗？</p><p>日高先生，说实话在好的意义上几乎没变。一直都是笑着面对大家。明明绝对很累，但在任何现场都不会露出严肃或者疲惫的表情。那种地方真的很职业，我每次都会被他的词汇量震到。MC真的会直接扎进心里。我是真的词汇量不行，所以特别羡慕。</p><p>————那TAIKI写rap歌词的时候，是不是也每次都很辛苦？</p><p>但不知道为什么，一写歌词的时候，话就会自己往外冒！有时候我自己都会吓一跳，「我居然能用这种词？」就觉得音乐的力量真的很夸张。家里人还会跟我说：「你平时说话也当自己在写歌词不行吗？」（笑）。</p><p>————（笑）一进入艺人模式，开关就切换了是吧。</p><p>是的（笑）。不过我觉得BMSG的人多少都有这种感觉。我会尽量多去看BMSG艺人的现场。平时看起来很可爱的人，一上台就完全炸开，气场直接拉满。真的像是被什么附体了一样。</p><p>————去现场，是想从前辈们的表演里吸收各种东西吗？</p><p>对。虽然在同一个事务所，但我是真的很尊敬大家，所以能抢的全部都想抢过来，全部都想学。比如SOTA原本是从舞者开始的，那他作为艺人站在舞台上的时候是怎么表现的，我都会仔细看，研究细节。他还会直接跟我说：「这样用力的话，拿着麦跳会更顺。」这种建议真的太实用了。我学到的东西非常多。</p><h3 id="从trainee阶段就能站上大舞台-这是最大的武器" tabindex="-1">从Trainee阶段就能站上大舞台，这是最大的武器 <a class="header-anchor" href="#从trainee阶段就能站上大舞台-这是最大的武器" aria-label="Permalink to &quot;从Trainee阶段就能站上大舞台，这是最大的武器&quot;">​</a></h3><p>————作为BMSG的一员，最让你感到自豪的是什么？</p><p>BMSG是一个会认可你去做喜欢的事的地方。只要你一直拼，成果就会出来。我有在韩国做练习生的朋友，他说每天就是无止境的练习。唱歌、跳舞、自主训练、跑步练体能。BMSG的Trainee阶段跟那种不太一样。我们从Trainee时期就能跟着巡演、上大舞台，提前适应现场。我觉得这真的是超级大的优势。</p><p>————不是当伴舞，而是在出道前就能作为一个艺人站上大型舞台，这确实很难得。</p><p>对啊。正常来说，Trainee哪有机会做自己的歌，更别说站上Arena规模的舞台。但在BMSG可以。这些经历等到出道之后一定会变成更高维度的活动基础。我也很期待自己到底能成长到什么程度。</p><p>还有一点，跟社长的距离真的很近，这也是BMSG的强项。普通公司里，社长应该是那种根本见不到的人。但在BMSG，他就在身边。而且他自己就是艺人，这点真的太重要了。他给的建议，是真的有分量的。</p><p>————公司规模越来越大，员工也在增加。你会有明显感受到这种变化吗？</p><p>会啊。自社大楼都建起来了……真的会感慨，「BMSG也长大了啊」。大家活动的范围越来越广，合作的制作人越来越多，现场规模也越来越大。我会很明确地感觉到，「BMSG接下来还会继续往上冲。」</p><p>————你也有越来越多机会接触比自己年纪更小的Trainee，心境上有变化吗？</p><p>大家关系都挺好。Trainee的KAIRI在听到「THE LAST PIECE」发表的时候，还发了很长一段信息跟我说「恭喜」。我当时就觉得，「好可爱啊」，真的很开心。</p><p>不过，我会刻意保持一种不太近、也不太远的距离。虽然同样是Trainee，但我心里一直有「不能输」的感觉。还有比我小一点的初一初二的孩子，练习的时候大家都很认真，也会直接互相说「这样改会不会更好？」这种意见。该认真就认真。</p><p>————最近SKY-HI先生对你说过的话里，有什么特别让你印象深刻的吗？</p><p>社长说的每一句话我都当成宝在收。每次都想说声「谢谢」然后给他拜一下那种（笑）。</p><p>今年「BMSG FES&#39;24」要发表「THE LAST PIECE」的消息，我觉得那是关系到我人生的一场表演，所以在正式演出前一天特地去问他意见。</p><p>社长跟我说：「TAIKI一路累积到现在的东西没有错，照你平常那样来，绝对能狠狠干一场。」</p><p>我当时真的觉得，他怎么能这么温柔。那句话直接变成了我的自信来源。</p><h3 id="感觉能吸收的东西我已经全部吸完了" tabindex="-1">感觉能吸收的东西我已经全部吸完了 <a class="header-anchor" href="#感觉能吸收的东西我已经全部吸完了" aria-label="Permalink to &quot;感觉能吸收的东西我已经全部吸完了&quot;">​</a></h3><p>————你是什么时候知道「THE LAST PIECE」要举办的？</p><p>在「BMSG FES&#39;24」正式演出前一周，在BE:FIRST和MAZZEL都在的场合听到发表。走到现在这一步确实很长，但前面还有更长的路。我希望能把这些年练出来的东西全部打出来。</p><p>说实话，我感觉自己现在能吸收的已经吸收得差不多了。接下来是怎么把这些素材“料理”成自己的风格。我想认真去想这件事。不只是事务所内部，我还想看更多国内外艺人的现场。也想去美国看。</p><p>————视野明显变大了。24年7月，ATEEZ在美国洛杉矶公演时，BE:FIRST担任开场嘉宾。你也去了现场对吧？感觉怎么样？</p><p>现场气氛完全跟日本不一样，我真的吓到了。看BE:FIRST的演出时，我差点直接哭出来。一起参加选秀的伙伴们，能在美国把现场点燃到这种程度，真的太夸张了。我当时心里只有一句话：「我也要更拼。」</p><p>————会有一点不甘心吗？</p><p>会。但不甘心这种感觉，我经历太多次了。所以那天更多的是发自内心的「恭喜！」</p><p>出发前，我其实不太理解为什么艺人都想去LA。后来有位艺人跟我说：「LA的气候和湿度完全不同，你可以想想在那种环境下写歌词会变成什么样。」</p><p>我在那边真的用全身去感受那种氛围和节奏。在LA我去了舞蹈教室，学习当地的groove，接触完全不同的文化。真的庆幸自己去了。</p><p>我也想跨过这个阶段。总有一天，我要在美国开现场。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>一边做AAA，一边在地下作为rapper活动的我，一直会幻想「如果能用现在的实力重来一次人生」「如果有理想的环境会怎样」——那种原本不可能的梦，被TAIKI变成了“可能”。</p><p>他是在地下成长起来的，现在正准备把那份技能向更广阔的世界释放。</p><p>想来，我自己也是“团体中的rapper”这根接力棒的继承者（虽然是异端）。我认为，正式把这根棒子交给TAIKI的时刻已经到了。</p><p>这条路很险。包括我在内，还没有人真正“踏破”它。其实，比起TAIKI对BMSG抱有的梦想，BMSG对他抱有的梦想更大。</p><p>看着他在那样的环境中如此天真、纯粹地享受并成长，我会由衷觉得，自己活到现在真好。</p><p>五年后站在世界中心的人是谁——他会和BMSG一起证明给大家看。</p></blockquote>',40)])])}const s=p(i,[["render",n]]);export{h as __pageData,s as default};
